import os
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, ConnectionError, NotFoundError
from functools import wraps
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

# --- Configuration ---
# Elasticsearch connection details
ELASTICSEARCH_HOST = os.environ.get('ELASTICSEARCH_HOST', 'localhost')
ELASTICSEARCH_PORT = int(os.environ.get('ELASTICSEARCH_PORT', 9200))
ELASTICSEARCH_INDEX = os.environ.get('ELASTICSEARCH_INDEX', 'products')
ELASTICSEARCH_TIMEOUT = int(os.environ.get('ELASTICSEARCH_TIMEOUT', 5)) # seconds
ELASTICSEARCH_MAX_RETRIES = int(os.environ.get('ELASTICSEARCH_MAX_RETRIES', 3))

# Search specific configurations
DEFAULT_PAGE_SIZE = int(os.environ.get('DEFAULT_PAGE_SIZE', 10))
MAX_PAGE_SIZE = int(os.environ.get('MAX_PAGE_SIZE', 100))
MAX_QUERY_LENGTH = int(os.environ.get('MAX_QUERY_LENGTH', 200)) # Max length for the 'q' parameter

# --- Elasticsearch Client Initialization ---
es = None
try:
    es = Elasticsearch(
        hosts=[{'host': ELASTICSEARCH_HOST, 'port': ELASTICSEARCH_PORT, 'scheme': 'http'}],
        timeout=ELASTICSEARCH_TIMEOUT,
        max_retries=ELASTICSEARCH_MAX_RETRIES,
        retry_on_timeout=True
    )
    if not es.ping():
        raise ConnectionError("Could not connect to Elasticsearch!")
    logger.info(f"Successfully connected to Elasticsearch at {ELASTICSEARCH_HOST}:{ELASTICSEARCH_PORT}")
except ConnectionError as e:
    logger.error(f"Failed to connect to Elasticsearch: {e}")
    es = None # Ensure es is None if connection fails
except Exception as e:
    logger.error(f"An unexpected error occurred during Elasticsearch connection: {e}")
    es = None

# --- Helper Functions and Decorators ---

def require_elasticsearch(f):
    """Decorator to ensure Elasticsearch is connected before handling a request."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if es is None:
            logger.error("Elasticsearch is not connected. Cannot process request.")
            return jsonify({"error": "Service unavailable: Elasticsearch connection failed"}), 503
        return f(*args, **kwargs)
    return decorated_function

def validate_query_parameter(param_name, max_length):
    """Decorator to validate a query parameter's length."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            param_value = request.args.get(param_name, '').strip()
            if len(param_value) > max_length:
                return jsonify({"error": f"Query parameter '{param_name}' exceeds maximum length of {max_length} characters"}), 400
            return f(*args, **kwargs)
        return decorated_function
    return decorator

# --- API Endpoint ---

@app.route('/api/search', methods=['GET'])
@require_elasticsearch
@validate_query_parameter('q', MAX_QUERY_LENGTH)
def search_products():
    """
    Searches for products in Elasticsearch based on a keyword query.
    GET /api/search?q=keyword[&page=1&size=10]
    """
    query = request.args.get('q', '').strip()
    if not query:
        return jsonify({"error": "Query parameter 'q' is required"}), 400

    try:
        page = int(request.args.get('page', 1))
        size = int(request.args.get('size', DEFAULT_PAGE_SIZE))
        if page < 1:
            page = 1
        if size < 1:
            size = DEFAULT_PAGE_SIZE
        if size > MAX_PAGE_SIZE:
            size = MAX_PAGE_SIZE
    except ValueError:
        return jsonify({"error": "Invalid 'page' or 'size' parameter. Must be integers."}), 400

    from_index = (page - 1) * size

    search_body = {
        "query": {
            "multi_match": {
                "query": query,
                "fields": ["name^3", "description", "category^2", "tags"], # Boost 'name' and 'category' fields
                "type": "best_fields",
                "fuzziness": "AUTO" # Allow for minor typos
            }
        },
        "size": size,
        "from": from_index,
        "highlight": { # Add highlighting for better user experience
            "fields": {
                "name": {},
                "description": {}
            }
        }
    }

    try:
        logger.info(f"Searching Elasticsearch for query: '{query}', page: {page}, size: {size}")
        res = es.search(index=ELASTICSEARCH_INDEX, body=search_body)

        hits = []
        for hit in res['hits']['hits']:
            source = hit['_source']
            source['id'] = hit['_id'] # Include document ID
            if 'highlight' in hit:
                source['highlight'] = hit['highlight'] # Include highlights
            hits.append(source)

        return jsonify({
            "query": query,
            "total_results": res['hits']['total']['value'],
            "page": page,
            "page_size": size,
            "results": hits
        }), 200

    except NotFoundError:
        logger.warning(f"Elasticsearch index '{ELASTICSEARCH_INDEX}' not found.")
        return jsonify({"error": f"Search index '{ELASTICSEARCH_INDEX}' not found. Please ensure it exists and contains data."}), 500
    except ConnectionError as e:
        logger.error(f"Elasticsearch connection error during search: {e}")
        return jsonify({"error": "Could not connect to Elasticsearch during search. Please try again later."}), 503
    except Exception as e:
        logger.exception(f"An unexpected error occurred during search for query '{query}': {e}")
        return jsonify({"error": "An internal server error occurred"}), 500

# --- Health Check Endpoint ---
@app.route('/health', methods=['GET'])
def health_check():
    """
    Provides a health check for the API and its dependencies.
    """
    status = {"api_status": "UP"}
    if es:
        try:
            if es.ping():
                status["elasticsearch_status"] = "UP"
            else:
                status["elasticsearch_status"] = "DOWN"
                status["elasticsearch_error"] = "Could not ping Elasticsearch"
        except Exception as e:
            status["elasticsearch_status"] = "DOWN"
            status["elasticsearch_error"] = str(e)
    else:
        status["elasticsearch_status"] = "DOWN"
        status["elasticsearch_error"] = "Elasticsearch client not initialized"

    if status.get("elasticsearch_status") == "DOWN":
        return jsonify(status), 503
    return jsonify(status), 200

